import type { DMMF } from '@prisma/dmmf'

/** Maps Prisma scalar type names to their TypeScript equivalents. */
const SCALAR_TYPE_MAP: Record<string, string> = {
  String: 'string',
  Int: 'number',
  Float: 'number',
  Decimal: 'number',
  BigInt: 'bigint',
  Boolean: 'boolean',
  DateTime: 'Date',
  Json: 'unknown',
  Bytes: 'Uint8Array',
}

/**
 * Returns the TypeScript type string for a given DMMF field, accounting for
 * list and optional modifiers.
 */
export function prismaTypeToTs(field: DMMF.Field): string {
  let base: string

  if (field.kind === 'scalar') {
    base = SCALAR_TYPE_MAP[field.type] ?? 'unknown'
  } else if (field.kind === 'enum' || field.kind === 'object') {
    base = field.type
  } else {
    base = 'unknown'
  }

  if (field.isList) {
    base = `${base}[]`
  }

  if (!field.isRequired) {
    base = `${base} | null`
  }

  return base
}

