import type { DMMF } from '@prisma/dmmf'

import { prismaTypeToTs } from './type-mapping'

/**
 * Returns the names of all `@id` fields on a model, falling back to `['id']`
 * when the model has no explicit primary key fields.
 */
function idFieldNames(model: DMMF.Model): string[] {
  const ids = model.fields.filter((f) => f.isId).map((f) => f.name)
  return ids.length > 0 ? ids : ['id']
}

/**
 * Returns field names that should be excluded from create/update `data`
 * payloads: `@id` fields, fields that carry a `@default` value, and all
 * relation (object-kind) fields.
 */
function nonWritableFieldNames(model: DMMF.Model): string[] {
  return model.fields
    .filter((f) => f.isId || f.hasDefaultValue || f.kind === 'object')
    .map((f) => f.name)
}

function generateEnumType(e: DMMF.DatamodelEnum): string {
  const values = e.values.map((v) => `'${v.name}'`).join(' | ')
  return `export type ${e.name} = ${values}`
}

function generateModelInterface(model: DMMF.Model): string {
  const lines = model.fields.map((field) => `  ${field.name}: ${prismaTypeToTs(field)}`)
  return [`export interface ${model.name} {`, ...lines, '}'].join('\n')
}

function generateFindManyArgs(model: DMMF.Model): string {
