import type { DMMF } from '@prisma/dmmf'
import { describe, expect, it } from 'vitest'

import { generateRestClient } from '../generate-rest-client'
import { generateTypes } from '../generate-types'
import { RestApiClientGenerator } from '../generator'
import { prismaTypeToTs } from '../type-mapping'

// ---------------------------------------------------------------------------
// Minimal DMMF fixture used across all tests
// ---------------------------------------------------------------------------

function makeField(overrides: Partial<DMMF.Field> & { name: string; type: string }): DMMF.Field {
  return {
    kind: 'scalar',
    isRequired: true,
    isList: false,
    isUnique: false,
    isId: false,
    isReadOnly: false,
    hasDefaultValue: false,
    ...overrides,
  }
}

const roleEnum: DMMF.DatamodelEnum = {
  name: 'Role',
  values: [
    { name: 'ADMIN', dbName: null },
    { name: 'USER', dbName: null },
  ],
}

const userModel: DMMF.Model = {
  name: 'User',
  dbName: null,
  schema: null,
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
  fields: [
    makeField({ name: 'id', type: 'String', isId: true }),
    makeField({ name: 'email', type: 'String', isUnique: true }),
    makeField({ name: 'name', type: 'String', isRequired: false }),
    makeField({ name: 'role', type: 'Role', kind: 'enum' }),
    makeField({ name: 'createdAt', type: 'DateTime', hasDefaultValue: true }),
    makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true, isRequired: false }),
  ],
}

const postModel: DMMF.Model = {
  name: 'Post',
  dbName: null,
  schema: null,
  uniqueFields: [],
  uniqueIndexes: [],
  primaryKey: null,
  fields: [
    makeField({ name: 'id', type: 'Int', isId: true }),
    makeField({ name: 'title', type: 'String' }),
    makeField({ name: 'content', type: 'String', isRequired: false }),
    makeField({ name: 'authorId', type: 'String' }),
    makeField({ name: 'author', type: 'User', kind: 'object', isRequired: false }),
  ],
}

// ---------------------------------------------------------------------------
// prismaTypeToTs
// ---------------------------------------------------------------------------

describe('prismaTypeToTs', () => {
  it.each([
    ['String', 'string'],
    ['Int', 'number'],
    ['Float', 'number'],
    ['Decimal', 'number'],
    ['BigInt', 'bigint'],
    ['Boolean', 'boolean'],
    ['DateTime', 'Date'],
    ['Json', 'unknown'],
    ['Bytes', 'Uint8Array'],
  ])('maps scalar %s → %s', (prismaType, expected) => {
    const field = makeField({ name: 'x', type: prismaType })
    expect(prismaTypeToTs(field)).toBe(expected)
  })

  it('maps an unknown scalar to unknown', () => {
    const field = makeField({ name: 'x', type: 'SomeFutureType' })
    expect(prismaTypeToTs(field)).toBe('unknown')
  })

  it('maps an enum field to its type name', () => {
    const field = makeField({ name: 'role', type: 'Role', kind: 'enum' })
    expect(prismaTypeToTs(field)).toBe('Role')
  })

  it('maps a relation (object) field to its type name', () => {
    const field = makeField({ name: 'author', type: 'User', kind: 'object' })
    expect(prismaTypeToTs(field)).toBe('User')
  })

  it('wraps list fields with []', () => {
    const field = makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true })
    expect(prismaTypeToTs(field)).toBe('Post[]')
  })

  it('appends | null for optional fields', () => {
    const field = makeField({ name: 'name', type: 'String', isRequired: false })
    expect(prismaTypeToTs(field)).toBe('string | null')
  })

  it('handles optional list fields', () => {
    const field = makeField({ name: 'posts', type: 'Post', kind: 'object', isList: true, isRequired: false })
    expect(prismaTypeToTs(field)).toBe('Post[] | null')
  })
})

// ---------------------------------------------------------------------------
// generateTypes
// ---------------------------------------------------------------------------

describe('generateTypes', () => {
  const output = generateTypes([userModel, postModel], [roleEnum])

  it('emits an enum union type', () => {
    expect(output).toContain("export type Role = 'ADMIN' | 'USER'")
  })

  it('emits a model interface for User', () => {
    expect(output).toContain('export interface User {')
    expect(output).toContain('  id: string')
    expect(output).toContain('  email: string')
    expect(output).toContain('  name: string | null')
    expect(output).toContain('  role: Role')
    expect(output).toContain('  createdAt: Date')
    expect(output).toContain('  posts: Post[] | null')
  })

  it('emits a model interface for Post', () => {
    expect(output).toContain('export interface Post {')
    expect(output).toContain('  id: number')
    expect(output).toContain('  title: string')
    expect(output).toContain('  content: string | null')
    expect(output).toContain('  authorId: string')
    expect(output).toContain('  author: User | null')
  })

  it('emits FindManyArgs with optional where/orderBy/skip/take', () => {
    expect(output).toContain('export type UserFindManyArgs = {')
    expect(output).toContain('  where?: Partial<User>')
    expect(output).toContain("  orderBy?: { [K in keyof User]?: 'asc' | 'desc' }")
    expect(output).toContain('  skip?: number')
    expect(output).toContain('  take?: number')
  })

  it('emits FindUniqueArgs with required where based on @id field', () => {
    expect(output).toContain('export type UserFindUniqueArgs = {')
    expect(output).toContain('    id: string')
  })

  it('emits CreateArgs that omits id, defaults, and relations', () => {
    expect(output).toContain('export type UserCreateArgs = {')
    // id (isId), createdAt (hasDefaultValue), and posts (object) are excluded
    expect(output).toContain("Omit<User, 'id' | 'createdAt' | 'posts'>")
  })

  it('emits UpdateArgs with where on id and Partial data omitting id and relations', () => {
    expect(output).toContain('export type UserUpdateArgs = {')
    expect(output).toContain("Partial<Omit<User, 'id' | 'posts'>>")
  })

  it('emits DeleteArgs with required where based on @id field', () => {
    expect(output).toContain('export type UserDeleteArgs = {')
    expect(output).toContain('    id: string')
  })

  it('uses integer id type for Post', () => {
    expect(output).toContain('export type PostFindUniqueArgs = {')
    expect(output).toContain('    id: number')
  })
})

// ---------------------------------------------------------------------------
// generateRestClient
// ---------------------------------------------------------------------------

describe('generateRestClient', () => {
  const output = generateRestClient([userModel, postModel])

  it('emits a RestApiClient class', () => {
    expect(output).toContain('export class RestApiClient {')
  })

  it('exposes a user property', () => {
    expect(output).toContain('readonly user = {')
  })

  it('exposes a post property', () => {
    expect(output).toContain('readonly post = {')
  })

  it('generates findMany using GET', () => {
    expect(output).toContain("this.#request('GET', `/users?")
  })

  it('generates findUnique using GET with id path segment', () => {
    expect(output).toContain("this.#request('GET', `/users/${")
    expect(output).toContain('args.where.id')
  })

  it('generates create using POST', () => {
    expect(output).toContain("this.#request('POST', '/users', args.data)")
  })

  it('generates update using PATCH', () => {
    expect(output).toContain("this.#request('PATCH', `/users/${")
  })

  it('generates delete using DELETE', () => {
    expect(output).toContain("this.#request('DELETE', `/users/${")
  })

  it('includes a private #request helper', () => {
    expect(output).toContain('async #request<T>')
    expect(output).toContain('response.ok')
  })

  it('strips trailing slash from baseUrl in constructor', () => {
    expect(output).toContain("this.#baseUrl = baseUrl.replace(/\\/$/, '')")
  })
})

// ---------------------------------------------------------------------------
// RestApiClientGenerator
// ---------------------------------------------------------------------------

describe('RestApiClientGenerator', () => {
  it('has the correct name', () => {
    const gen = new RestApiClientGenerator()
    expect(gen.name).toBe('rest-api-client')
  })

  it('getManifest returns expected defaultOutput and prettyName', async () => {
    const gen = new RestApiClientGenerator()
    // getManifest receives a GeneratorConfig but the implementation ignores it
    const manifest = await gen.getManifest({} as never)
    expect(manifest.defaultOutput).toBe('./generated/rest-client')
    expect(manifest.prettyName).toBe('REST API Client')
  })
})

